    private final ExpressionParser parser;

    public ExpressionService() {
        // The parser is thread-safe and can be reused.
        this.parser = new SpelExpressionParser();
    }

    /**
     * Evaluates a SpEL expression provided by a user.
     *
     * @param expression The SpEL expression string (e.g., "2 + 2", "'Hello' + ' World'")
     * @return The result of the evaluation
     * @throws IllegalArgumentException if the expression is null or empty
     * @throws RuntimeException if parsing or evaluation fails
     */
    public Object evaluateUserExpression(String expression) {
        if (expression == null || expression.trim().isEmpty()) {
            throw new IllegalArgumentException("Expression cannot be null or empty");
        }

        try {
            // SECURITY CRITICAL:
            // We use SimpleEvaluationContext instead of StandardEvaluationContext.
            // StandardEvaluationContext allows full power of Java (including T(Runtime).exec(...)),
            // which leads to Remote Code Execution (RCE) vulnerabilities when handling user input.
            // SimpleEvaluationContext is designed for untrusted sources and supports a limited subset
            // of SpEL (properties, methods, and arithmetic) while blocking static type references.
            EvaluationContext context = SimpleEvaluationContext.forReadOnlyDataBinding().build();

            Expression exp = parser.parseExpression(expression);
            return exp.getValue(context);

        } catch (ParseException | EvaluationException e) {
            // Wrapping SpEL specific exceptions into a generic runtime exception
            // to abstract the underlying technology from the caller.
            throw new RuntimeException("Error evaluating expression: " + expression, e);
        }
    }
}
